3	namespace App\Models;
4	
5	use Illuminate\Database\Eloquent\Builder;
6	use Illuminate\Database\Eloquent\Model;
7	use Illuminate\Database\Eloquent\SoftDeletes;
8	use Illuminate\Database\Eloquent\Concerns\HasUuids;
9	use Illuminate\Database\Eloquent\Relations\BelongsTo;
10	
11	class Queue extends Model
12	{
13	    use HasUuids, SoftDeletes;
14	
15	    protected $keyType = 'string';
16	    public $incrementing = false;
17	
18	    // Station enum (sesuai Section 11.1 Architecture)
19	    public const STATION_ADMISI       = 'ADMISI';
20	    public const STATION_TRIASE       = 'TRIASE';
21	    public const STATION_REFRAKSIONIS = 'REFRAKSIONIS';
22	    public const STATION_DOKTER       = 'DOKTER';
23	    public const STATION_PENUNJANG    = 'PENUNJANG';
24	    public const STATION_BEDAH        = 'BEDAH';
25	    public const STATION_KASIR        = 'KASIR';
26	    public const STATION_FARMASI      = 'FARMASI';
27	
28	    public const STATIONS = [
29	        self::STATION_ADMISI,
30	        self::STATION_TRIASE,
31	        self::STATION_REFRAKSIONIS,
32	        self::STATION_DOKTER,
33	        self::STATION_PENUNJANG,
34	        self::STATION_BEDAH,
35	        self::STATION_KASIR,
36	        self::STATION_FARMASI,
37	    ];
38	
39	    // Prefix mapping (queue_number = prefix + sequence).
40	    // TRIASE & REFRAKSIONIS share prefix "TR" — pasien yg sama dilayani paralel
41	    // di kedua stasiun dengan satu nomor antrean (mis. TR-007).
42	    public const PREFIX_MAP = [
43	        self::STATION_ADMISI       => 'A',
44	        self::STATION_TRIASE       => 'TR',
45	        self::STATION_REFRAKSIONIS => 'TR',
46	        self::STATION_DOKTER       => 'D',
47	        self::STATION_PENUNJANG    => 'P',
48	        self::STATION_BEDAH        => 'B',
49	        self::STATION_KASIR        => 'K',
50	        self::STATION_FARMASI      => 'F',
51	    ];
52	
53	    // Stasiun yang berbagi prefix & sequence (paralel).
54	    public const SHARED_PREFIX_GROUPS = [
55	        'TR' => [self::STATION_TRIASE, self::STATION_REFRAKSIONIS],
56	    ];
57	
58	    // Status enum
59	    public const STATUS_WAITING     = 'WAITING';
60	    public const STATUS_CALLED      = 'CALLED';
61	    public const STATUS_IN_PROGRESS = 'IN_PROGRESS';
62	    public const STATUS_COMPLETED   = 'COMPLETED';
63	    public const STATUS_CANCELLED   = 'CANCELLED';
64	
65	    // Sub-status khusus baris DOKTER saat alur penunjang (pasien tetap milik dokter):
66	    //   DI_PENUNJANG      = pasien sedang di stasiun penunjang (baris turun ke bawah)
67	    //   SELESAI_PENUNJANG = semua hasil selesai, siap dilanjut dokter (baris naik ke atas)
68	    public const STATUS_AT_PENUNJANG    = 'DI_PENUNJANG';
69	    public const STATUS_PENUNJANG_DONE  = 'SELESAI_PENUNJANG';
70	
71	    public const ACTIVE_STATUSES = [
72	        self::STATUS_WAITING,
73	        self::STATUS_CALLED,
74	        self::STATUS_IN_PROGRESS,
75	    ];
76	
77	    protected $fillable = [
78	        'visit_id',
79	        'station',
80	        'queue_prefix',
81	        'queue_sequence',
82	        'queue_number',
83	        'status',
84	        'called_at',
85	        'started_at',
86	        'completed_at',
87	    ];
88	
89	    protected $casts = [
90	        'called_at'    => 'datetime',
91	        'started_at'   => 'datetime',
92	        'completed_at' => 'datetime',
93	    ];
94	
95	    public function visit(): BelongsTo
96	    {
97	        return $this->belongsTo(Visit::class);
98	    }
99	
100	    // ---------------------------------------------------------------------
101	    // SCOPES
102	    // ---------------------------------------------------------------------
103	
104	    public function scopeToday(Builder $q): Builder
105	    {
106	        return $q->whereDate('created_at', today());
107	    }
108	
109	    public function scopeByStation(Builder $q, string $station): Builder
110	    {
111	        return $q->where('station', $station);
112	    }
113	
114	    public function scopeActive(Builder $q): Builder
115	    {
116	        return $q->whereIn('status', self::ACTIVE_STATUSES);
117	    }
118	
119	    public function scopeWaiting(Builder $q): Builder
120	    {
121	        return $q->where('status', self::STATUS_WAITING);
122	    }
123	
124	    // ---------------------------------------------------------------------
125	    // HELPERS
126	    // ---------------------------------------------------------------------
127	
128	    public static function prefixFor(string $station): string
129	    {
130	        return self::PREFIX_MAP[$station] ?? 'X';
131	    }
132	}
