2	
3	namespace App\Services;
4	
5	use App\Events\AdmisiQueueUpdated;
6	use App\Events\AntreanTvUpdated;
7	use App\Events\TriaseQueueUpdated;
8	use App\Models\DiagnosticOrder;
9	use App\Models\Prescription;
10	use App\Models\Queue;
11	use App\Models\SurgerySchedule;
12	use App\Models\SystemLog;
13	use App\Models\Visit;
14	use Illuminate\Database\Eloquent\Collection;
15	use Illuminate\Http\Request;
16	use Illuminate\Support\Facades\DB;
17	
18	/**
19	 * Sentral logic antrian — referensi: ARCHITECTURE.md Section 11 (Service Flow).
20	 *
21	 * Alur:  A → (TRIASE & REFRAKSIONIS paralel) → D → (P? / B?) → K → F → SELESAI
22	 *
23	 * Setiap "selesaiAntrian" memanggil advanceFromStation() yang:
24	 *   1. Tandai baris queues sekarang -> COMPLETED
25	 *   2. Tentukan station berikutnya (lihat resolveNextStation)
26	 *   3. Enqueue baris baru di station tujuan (atau set visit.current_station=SELESAI)
27	 *   4. Broadcast event Reverb yang relevan
28	 *
29	 * resolveNextStation kontrak:
30	 *   string         → enqueue baris baru di station itu
31	 *   array<string>  → enqueue multi paralel
32	 *   END_OF_FLOW    → pasien pulang (current_station=SELESAI)
33	 *   NO_OP          → tutup queue saja, no enqueue, current_station tetap (mis. partner TR sudah trigger next)
34	 *   null           → gate belum passed, antrian tidak boleh ditutup (throw)
35	 */
36	class QueueService
37	{
38	    public const END_OF_FLOW = '__END__';
39	    public const NO_OP       = '__NOOP__';
40	
41	    public function __construct(private readonly Request $request) {}
42	
43	    // =========================================================================
44	    // GENERATE NUMBER (thread-safe per station per hari)
45	    // =========================================================================
46	
47	    /**
48	     * Generate nomor antrian.
49	     *
50	     * Untuk station DOKTER, prefix bisa dynamic berdasarkan nomor ruangan:
51	     *   room="1" → prefix="D1", queue_number="D1-001"
52	     *   room="2" → prefix="D2", queue_number="D2-001"
53	     *   room=null → prefix="D",  queue_number="D-001"  (fallback)
54	     *
55	     * Sequence dihitung PER PREFIX per hari, sehingga D1 dan D2
56	     * punya counter terpisah (D1-001 dan D2-001 bisa exist bersamaan).
57	     */
58	    public function generateQueueNumber(string $station, ?string $room = null): array
59	    {
60	        if ($station === Queue::STATION_DOKTER && $room !== null && $room !== '') {
61	            $prefix = 'D' . $room;
62	
63	            $lastSeq = Queue::where('station', Queue::STATION_DOKTER)
64	                ->where('queue_prefix', $prefix)
65	                ->whereDate('created_at', today())
66	                ->max('queue_sequence') ?? 0;
67	
68	            $sequence = $lastSeq + 1;
69	        } else {
70	            $prefix = Queue::prefixFor($station);
71	
72	            // Stasiun yang share prefix (mis. TRIASE + REFRAKSIONIS = "TR")
73	            // perlu sequence yang juga shared supaya nomor tidak collision.
74	            $stationsForSeq = Queue::SHARED_PREFIX_GROUPS[$prefix] ?? [$station];
75	
76	            $lastSeq = Queue::whereIn('station', $stationsForSeq)
77	                ->whereDate('created_at', today())
78	                ->max('queue_sequence') ?? 0;
79	
80	            $sequence = $lastSeq + 1;
81	        }
82	
83	        return [
84	            'queue_prefix'   => $prefix,
85	            'queue_sequence' => $sequence,
86	            'queue_number'   => $prefix . '-' . str_pad($sequence, 3, '0', STR_PAD_LEFT),
87	        ];
88	    }
89	
90	    // =========================================================================
91	    // CORE ACTIONS
92	    // =========================================================================
93	
94	    /**
95	     * Buat antrian baru di station tertentu untuk sebuah visit.
96	     * Broadcast `added` ke channel `antrean-tv` agar TV langsung lihat row baru.
97	     *
98	     * Untuk station DOKTER, room diambil otomatis dari visit.doctorSchedule.room
99	     * sehingga queue_number menjadi "D{room}-xxx".
100	     *
101	     * @param  array|null  $sharedNumber  Optional: pakai nomor pre-generated
102	     *                                    (untuk pair TRIASE+REFRAKSIONIS yg share TR-NNN)
103	     */
104	    public function enqueue(string $visitId, string $station, ?array $sharedNumber = null): Queue
105	    {
106	        $this->assertStation($station);
107	
108	        if ($sharedNumber) {
109	            $data = $sharedNumber;
110	        } elseif ($station === Queue::STATION_DOKTER) {
111	            // Ambil ruangan dokter yang di-assign saat admisi
112	            $visit = \App\Models\Visit::with('doctorSchedule')->find($visitId);
113	            $room  = $visit?->doctorSchedule?->room;
114	            $data  = $this->generateQueueNumber($station, $room);
115	        } else {
116	            $data = $this->generateQueueNumber($station);
117	        }
118	
119	        $queue = Queue::create([
120	            'visit_id'       => $visitId,
121	            'station'        => $station,
122	            'queue_prefix'   => $data['queue_prefix'],
123	            'queue_sequence' => $data['queue_sequence'],
124	            'queue_number'   => $data['queue_number'],
125	            'status'         => Queue::STATUS_WAITING,
126	        ]);
127	
128	        $this->broadcastQueueUpdate($queue->fresh(['visit.patient']), 'added');
129	
130	        return $queue;
131	    }
132	
133	    /**
134	     * Data tiket Dokter (D-NNN) untuk sebuah visit — dipakai stasiun TR untuk
135	     * mencetak tiket lanjutan setelah gate Triase+Refraksionis lolos & antrian
136	     * DOKTER otomatis dibuat (lihat checkReadyForDoctor di Perawat/RefraksiService).
137	     * Return null kalau antrian DOKTER belum ada (partner TR belum finalize).
138	     */
139	    public function getDoctorTicket(string $visitId): ?array
140	    {
141	        $queue = Queue::byStation(Queue::STATION_DOKTER)
142	            ->where('visit_id', $visitId)
143	            ->whereDate('created_at', today())
144	            ->latest('created_at')
145	            ->first();
146	
147	        if (! $queue) {
148	            return null;
149	        }
150	
151	        $sched = Visit::with('doctorSchedule.employee')->find($visitId)?->doctorSchedule;
152	
153	        return [
154	            'queue_number' => $queue->queue_number,
155	            'poliklinik'   => $sched?->poliklinik,
156	            'room'         => $sched?->room,
157	            'doctor_name'  => $sched?->employee?->name,
158	        ];
159	    }
160	
161	    /**
162	     * Panggil antrian:
163	     *   - WAITING     → CALLED (panggilan awal)
164	     *   - CALLED      → CALLED (panggil ulang, pasien belum hadir/menjawab)
165	     *   - IN_PROGRESS → IN_PROGRESS (panggil ulang saat pasien sedang diperiksa,
166	     *                   mis. perlu kembali dari ruang ganti). Status tetap, hanya
167	     *                   `called_at` di-refresh + broadcast ulang ke speaker/TV.
168	     * COMPLETED/CANCELLED ditolak.
169	     */
170	    public function panggil(string $queueId): Queue
171	    {
172	        $queue = Queue::findOrFail($queueId);
173	
174	        // SELESAI_PENUNJANG (& DI_PENUNJANG) tetap bisa dipanggil — dokter melanjutkan pemeriksaan.
175	        $callable = array_merge(Queue::ACTIVE_STATUSES, [Queue::STATUS_AT_PENUNJANG, Queue::STATUS_PENUNJANG_DONE]);
176	        if (! in_array($queue->status, $callable, true)) {
177	            throw new \Exception('Antrian sudah selesai atau dibatalkan — tidak bisa dipanggil.', 422);
178	        }
179	
180	        $queue->update([
181	            'status'    => $queue->status === Queue::STATUS_IN_PROGRESS
182	                ? Queue::STATUS_IN_PROGRESS   // pertahankan IN_PROGRESS saat re-call
183	                : Queue::STATUS_CALLED,
184	            'called_at' => now(),
185	        ]);
186	
187	        $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
188	
189	        return $queue->fresh(['visit.patient']);
190	    }
191	
192	    /**
193	     * Mulai layanan: CALLED -> IN_PROGRESS.
194	     */
195	    public function mulai(string $queueId): Queue
196	    {
197	        $queue = Queue::findOrFail($queueId);
198	
199	        if ($queue->status !== Queue::STATUS_CALLED) {
200	            throw new \Exception('Panggil pasien terlebih dahulu.', 422);
201	        }
202	
203	        $queue->update([
204	            'status'     => Queue::STATUS_IN_PROGRESS,
205	            'started_at' => now(),
206	        ]);
207	
208	        $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
209	
210	        return $queue->fresh(['visit.patient']);
211	    }
212	
213	    /**
214	     * Lewati / skip pasien: turunkan SATU posisi — tukar urutan dengan pasien
215	     * berikutnya yang masih aktif (WAITING/CALLED) di station yang sama. Bila
216	     * pasien ini sudah paling bawah (tak ada yang aktif di bawahnya), tetap di
217	     * tempat (no-op posisi). Status selalu di-reset ke WAITING (kalau tadinya
218	     * CALLED, panggilannya dibatalkan).
219	     */
220	    public function lewati(string $queueId): Queue
221	    {
222	        return DB::transaction(function () use ($queueId) {
223	            $queue = Queue::whereIn('status', [Queue::STATUS_WAITING, Queue::STATUS_CALLED])
224	                ->lockForUpdate()
225	                ->findOrFail($queueId);
226	
227	            // Pasien berikutnya = baris aktif dengan queue_sequence terkecil yang
228	            // masih lebih besar dari baris ini (kandidat layanan setelah ini).
229	            $next = Queue::byStation($queue->station)
230	                ->whereDate('created_at', today())
231	                ->whereIn('status', [Queue::STATUS_WAITING, Queue::STATUS_CALLED])
232	                ->where('id', '!=', $queue->id)
233	                ->where('queue_sequence', '>', $queue->queue_sequence)
234	                ->orderBy('queue_sequence')
235	                ->lockForUpdate()
236	                ->first();
237	
238	            if ($next) {
239	                // Tukar urutan: pasien ini turun 1, pasien berikutnya naik 1.
240	                $thisSeq = $queue->queue_sequence;
241	                $nextSeq = $next->queue_sequence;
242	                $next->update(['queue_sequence' => $thisSeq]);
243	                $queue->update([
244	                    'queue_sequence' => $nextSeq,
245	                    'status'         => Queue::STATUS_WAITING,
246	                    'called_at'      => null,
247	                ]);
248	                $this->broadcastQueueUpdate($next->fresh(['visit.patient']));
249	            } else {
250	                // Sudah paling bawah — cuma reset status (batalkan panggilan bila CALLED).
251	                $queue->update([
