285	    /**
286	     * Tandai antrian COMPLETED + buat antrian baru di station berikutnya
287	     * berdasarkan aturan transisi Section 11.3.
288	     *
289	     * @return array{queue: Queue, visit: Visit, next_station: ?string, next_queue: ?Queue}
290	     */
291	    public function advanceFromStation(string $queueId, string $expectedStation): array
292	    {
293	        $result = DB::transaction(function () use ($queueId, $expectedStation) {
294	            $queue = Queue::with('visit')->findOrFail($queueId);
295	
296	            if ($queue->station !== $expectedStation) {
297	                throw new \Exception(
298	                    "Station antrian tidak cocok: expected={$expectedStation}, actual={$queue->station}.",
299	                    422
300	                );
301	            }
302	
303	            if ($queue->status === Queue::STATUS_COMPLETED) {
304	                throw new \Exception('Antrian sudah ditutup.', 422);
305	            }
306	
307	            // 1. Resolve next station SEBELUM close — bisa throw kalau gate belum passed
308	            $visit       = $queue->visit;
309	            $nextStation = $this->resolveNextStation($visit, $expectedStation);
310	
311	            if ($nextStation === null) {
312	                throw new \Exception(
313	                    "Antrian {$expectedStation} belum bisa diselesaikan — sub-task belum lengkap.",
314	                    422
315	                );
316	            }
317	
318	            // 2. Close current queue
319	            $queue->update([
320	                'status'       => Queue::STATUS_COMPLETED,
321	                'completed_at' => now(),
322	            ]);
323	
324	            // 3. Enqueue next / END_OF_FLOW
325	            $nextQueue       = null;
326	            $nextStationName = null;
327	
328	            if ($nextStation === self::END_OF_FLOW) {
329	                $visit->update(['current_station' => 'SELESAI']);
330	                $nextStationName = 'SELESAI';
331	            } elseif ($nextStation === self::NO_OP) {
332	                $nextStationName = 'NO_OP';
333	            } elseif (is_array($nextStation)) {
334	                // Cek apakah semua station di array share prefix yang sama
335	                // (mis. [TRIASE, REFRAKSIONIS] → keduanya prefix "TR"). Kalau iya,
336	                // generate SATU nomor antrean dan terapkan ke semua baris.
337	                $prefixes = array_unique(array_map(fn ($s) => Queue::prefixFor($s), $nextStation));
338	                $shared   = count($prefixes) === 1 ? $this->generateQueueNumber($nextStation[0]) : null;
339	
340	                foreach ($nextStation as $st) {
341	                    $this->enqueue($visit->id, $st, $shared);
342	                }
343	
344	                $visit->update(['current_station' => $nextStation[0]]);
345	                $nextStationName = implode('+', $nextStation);
346	            } else {
347	                $nextQueue = $this->enqueue($visit->id, $nextStation);
348	                $visit->update(['current_station' => $nextStation]);
349	                $nextStationName = $nextStation;
350	            }
351	
352	            $this->log(
353	                auth('api')->id(),
354	                'ADVANCE_QUEUE',
355	                Visit::class,
356	                $visit->id,
357	                "Selesai {$expectedStation} → {$nextStationName}"
358	            );
359	
360	            $this->broadcastQueueUpdate($queue->fresh(['visit.patient']));
361	
362	            return [
363	                'queue'        => $queue->fresh(['visit.patient']),
364	                'visit'        => $visit->fresh(['patient', 'queues']),
365	                'next_station' => $nextStationName,
366	                'next_queue'   => $nextQueue,
367	            ];
368	        });
369	
370	        // Lapor waktu antrean ke BPJS SETELAH commit (post-transaction) — non-blocking:
371	        // kegagalan/timeout/credential-kosong tidak boleh membatalkan transisi lokal.
372	        $this->reportAntreanWaktu($result['visit'] ?? null, $expectedStation, $result['next_station'] ?? null);
373	
374	        return $result;
375	    }
