377	    /**
378	     * Kirim updatewaktu ke BPJS Antrean untuk kunjungan BPJS yang punya kode booking.
379	     * taskid BPJS dipetakan dari station: DOKTER mulai=3/selesai=4, FARMASI mulai=5/selesai=6.
380	     * Selalu dibungkus try/catch + hanya jika ANTREAN aktif — TIDAK pernah melempar.
381	     */
382	    private function reportAntreanWaktu(?Visit $visit, string $fromStation, ?string $nextStation): void
383	    {
384	        try {
385	            if (! $visit || $visit->guarantor_type !== 'BPJS' || empty($visit->bpjs_booking_code)) {
386	                return;
387	            }
388	
389	            $antrean = app(\App\Services\BpjsAntreanService::class);
390	            if (! $antrean->isEnabled()) {
391	                return;
392	            }
393	
394	            // Pemetaan taskid: selesai di station = lapor task selesai station tsb.
395	            $taskMap = [
396	                'DOKTER'  => 4, // selesai layan poli
397	                'FARMASI' => 6, // selesai farmasi
398	                'KASIR'   => 7, // selesai (pulang)
399	            ];
400	            $taskId = $taskMap[$fromStation] ?? null;
401	            if ($taskId === null) {
402	                return; // station lain (ADMISI/TRIASE/dll) tidak wajib lapor per BPJS
403	            }
404	
405	            $antrean->updateWaktuAntrean([
406	                'kodebooking' => $visit->bpjs_booking_code,
407	                'taskid'      => $taskId,
408	                'waktu'       => (int) (microtime(true) * 1000),
409	            ], $visit->id);
410	        } catch (\Throwable $e) {
411	            // Diam-diam — sudah tercatat di bpjs_antrean_logs lewat service; jangan ganggu flow.
412	            \Illuminate\Support\Facades\Log::warning('BPJS updatewaktu gagal: ' . $e->getMessage());
413	        }
414	    }
