416	    /**
417	     * Tentukan station berikutnya berdasarkan kondisi visit + aturan Section 11.3.
418	     *
419	     * Return: string | array | null
420	     *   - string  : single next station
421	     *   - array   : multi parallel (mis. [TRIASE, REFRAKSIONIS])
422	     *   - null    : pasien pulang (SELESAI)
423	     */
424	    public function resolveNextStation(Visit $visit, string $fromStation): string|array|null
425	    {
426	        return match ($fromStation) {
427	            Queue::STATION_ADMISI       => [Queue::STATION_TRIASE, Queue::STATION_REFRAKSIONIS],
428	            Queue::STATION_TRIASE       => $this->nextAfterTriaseOrRefraksi($visit),
429	            Queue::STATION_REFRAKSIONIS => $this->nextAfterTriaseOrRefraksi($visit),
430	            Queue::STATION_DOKTER       => $this->nextAfterDokter($visit),
431	            Queue::STATION_PENUNJANG    => $this->nextAfterPenunjang($visit), // balik ke dokter (anti-duplikat)
432	            Queue::STATION_BEDAH        => Queue::STATION_KASIR,
433	            Queue::STATION_KASIR        => $this->nextAfterKasir($visit),
434	            Queue::STATION_FARMASI      => self::END_OF_FLOW, // pasien pulang
435	            default                     => null,
436	        };
437	    }
438	
439	    /**
440	     * TRIASE atau REFRAKSIONIS selesai → DOKTER hanya jika keduanya sudah finalize.
441	     * Jika belum, tetap di station yg sama (return null = jangan enqueue baru).
442	     *
443	     * Khusus visit PREOP_BEDAH: gate paralel sama (TR+REF wajib selesai), tapi
444	     * transisi ke BEDAH dilakukan eksplisit lewat PerawatService::kirimKeBedah()
445	     * (tombol manual). Auto-advance dimatikan untuk mencegah pasien tidak sengaja
446	     * didorong ke bedah hanya karena finalize asesmen.
447	     */
448	    private function nextAfterTriaseOrRefraksi(Visit $visit): ?string
449	    {
450	        $visit->loadMissing(['nurseAssessment', 'refractionRecord']);
451	
452	        $triaseDone   = (bool) $visit->nurseAssessment?->is_finalized;
453	        $refraksiDone = (bool) $visit->refractionRecord?->is_finalized;
454	
455	        if (! $triaseDone || ! $refraksiDone) {
456	            // Gate belum passed — antrian tidak boleh ditutup
457	            return null;
458	        }
459	
460	        // PREOP_BEDAH: jangan auto-advance — tunggu tombol "Kirim ke Bedah".
461	        // Sub-task lain (mis. refraksi finalize duluan) tetap NO_OP saat partner
462	        // sudah selesai supaya antrean asal boleh ditutup.
463	        if ($visit->visit_type === 'PREOP_BEDAH') {
464	            return self::NO_OP;
465	        }
466	
467	        // Partner (sub-task lain) sudah trigger transisi ke DOKTER → tutup saja, no-op
468	        $alreadyQueued = Queue::byStation(Queue::STATION_DOKTER)
469	            ->where('visit_id', $visit->id)
470	            ->today()
471	            ->exists();
472	
473	        return $alreadyQueued ? self::NO_OP : Queue::STATION_DOKTER;
474	    }
475	
476	    /**
477	     * DOKTER selesai → urutan prioritas:
478	     *   1. Ada DiagnosticOrder REQUESTED/IN_PROGRESS → PENUNJANG
479	     *   2. Planning BEDAH dengan jadwal operasi HARI INI → BEDAH
480	     *      (planning BEDAH dengan jadwal hari lain → tetap lanjut ke KASIR;
481	     *       saat hari operasi tiba pasien daftar ulang dari ADMISI)
482	     *   3. Else → KASIR
483	     */
484	    private function nextAfterDokter(Visit $visit): string
485	    {
486	        // 1. Order penunjang yang masih open?
487	        $hasOpenOrder = DiagnosticOrder::where('visit_id', $visit->id)
488	            ->whereIn('status', ['REQUESTED', 'IN_PROGRESS'])
489	            ->exists();
490	
491	        if ($hasOpenOrder) {
492	            return Queue::STATION_PENUNJANG;
493	        }
494	
495	        // 2. Surgery schedule HARI INI?
496	        $visit->loadMissing('doctorExamination');
497	        $exam = $visit->doctorExamination;
498	
499	        if ($exam && $exam->planning === 'BEDAH' && $exam->surgery_schedule_id) {
500	            $isToday = SurgerySchedule::where('id', $exam->surgery_schedule_id)
501	                ->whereDate('scheduled_date', today())
502	                ->whereIn('status', ['SCHEDULED', 'IN_PROGRESS'])
503	                ->exists();
504	
505	            if ($isToday) {
506	                return Queue::STATION_BEDAH;
507	            }
508	            // Jadwal hari lain → pasien pulang via KASIR & FARMASI, kembali di hari operasi.
509	        }
510	
511	        // 3. Default
512	        return Queue::STATION_KASIR;
513	    }
514	
515	    /**
516	     * PENUNJANG selesai → balik ke DOKTER. Tapi bila baris DOKTER pasien masih hidup
517	     * (di-pause saat dikirim ke penunjang), jangan buat baris baru — PenunjangService
518	     * ::requeueToDokter yang menaikkannya kembali. NO_OP mencegah duplikat.
519	     */
520	    private function nextAfterPenunjang(Visit $visit): string
521	    {
522	        $hasLiveDokter = Queue::byStation(Queue::STATION_DOKTER)
523	            ->where('visit_id', $visit->id)
524	            ->today()
525	            ->whereNotIn('status', [Queue::STATUS_COMPLETED, Queue::STATUS_CANCELLED])
526	            ->exists();
527	
528	        return $hasLiveDokter ? self::NO_OP : Queue::STATION_DOKTER;
529	    }
530	
531	    /**
532	     * KASIR selesai → FARMASI jika ada resep, else SELESAI.
533	     */
534	    private function nextAfterKasir(Visit $visit): string
535	    {
536	        $hasPrescription = Prescription::where('visit_id', $visit->id)
537	            ->whereIn('status', ['DRAFT', 'SUBMITTED', 'DISPENSING'])
538	            ->exists();
539	
540	        return $hasPrescription ? Queue::STATION_FARMASI : self::END_OF_FLOW;
541	    }
